88	    /**
89	     * Create a new gate instance.
90	     *
91	     * @param  \Illuminate\Contracts\Container\Container  $container
92	     * @param  callable  $userResolver
93	     * @param  array  $abilities
94	     * @param  array  $policies
95	     * @param  array  $beforeCallbacks
96	     * @param  array  $afterCallbacks
97	     * @param  callable|null  $guessPolicyNamesUsingCallback
98	     */
99	    public function __construct(
100	        Container $container,
101	        callable $userResolver,
102	        array $abilities = [],
103	        array $policies = [],
104	        array $beforeCallbacks = [],
105	        array $afterCallbacks = [],
106	        ?callable $guessPolicyNamesUsingCallback = null,
107	    ) {
108	        $this->policies = $policies;
109	        $this->container = $container;
110	        $this->abilities = $abilities;
111	        $this->userResolver = $userResolver;
112	        $this->afterCallbacks = $afterCallbacks;
113	        $this->beforeCallbacks = $beforeCallbacks;
114	        $this->guessPolicyNamesUsingCallback = $guessPolicyNamesUsingCallback;
115	    }
