117	    /**
118	     * Determine if a given ability has been defined.
119	     *
120	     * @param  \UnitEnum|array|string  $ability
121	     * @return bool
122	     */
123	    public function has($ability)
124	    {
125	        $abilities = is_array($ability) ? $ability : func_get_args();
126	
127	        foreach ($abilities as $ability) {
128	            if (! isset($this->abilities[enum_value($ability)])) {
129	                return false;
130	            }
131	        }
132	
133	        return true;
134	    }
