136	    /**
137	     * Perform an on-demand authorization check. Throw an authorization exception if the condition or callback is false.
138	     *
139	     * @param  \Illuminate\Auth\Access\Response|\Closure|bool  $condition
140	     * @param  string|null  $message
141	     * @param  string|null  $code
142	     * @return \Illuminate\Auth\Access\Response
143	     *
144	     * @throws \Illuminate\Auth\Access\AuthorizationException
145	     */
146	    public function allowIf($condition, $message = null, $code = null)
147	    {
148	        return $this->authorizeOnDemand($condition, $message, $code, true);
149	    }
150	
151	    /**
152	     * Perform an on-demand authorization check. Throw an authorization exception if the condition or callback is true.
153	     *
154	     * @param  \Illuminate\Auth\Access\Response|\Closure|bool  $condition
155	     * @param  string|null  $message
156	     * @param  string|null  $code
157	     * @return \Illuminate\Auth\Access\Response
158	     *
159	     * @throws \Illuminate\Auth\Access\AuthorizationException
160	     */
161	    public function denyIf($condition, $message = null, $code = null)
162	    {
163	        return $this->authorizeOnDemand($condition, $message, $code, false);
164	    }
165	
166	    /**
167	     * Authorize a given condition or callback.
168	     *
169	     * @param  \Illuminate\Auth\Access\Response|\Closure|bool  $condition
170	     * @param  string|null  $message
171	     * @param  string|null  $code
172	     * @param  bool  $allowWhenResponseIs
173	     * @return \Illuminate\Auth\Access\Response
174	     *
175	     * @throws \Illuminate\Auth\Access\AuthorizationException
176	     */
177	    protected function authorizeOnDemand($condition, $message, $code, $allowWhenResponseIs)
178	    {
179	        $user = $this->resolveUser();
180	
181	        if ($condition instanceof Closure) {
182	            $response = $this->canBeCalledWithUser($user, $condition)
183	                ? $condition($user)
184	                : new Response(false, $message, $code);
185	        } else {
186	            $response = $condition;
187	        }
188	
189	        return ($response instanceof Response ? $response : new Response(
190	            (bool) $response === $allowWhenResponseIs, $message, $code
191	        ))->authorize();
192	    }
