194	    /**
195	     * Define a new ability.
196	     *
197	     * @param  \UnitEnum|string  $ability
198	     * @param  callable|array|string  $callback
199	     * @return $this
200	     *
201	     * @throws \InvalidArgumentException
202	     */
203	    public function define($ability, $callback)
204	    {
205	        $ability = enum_value($ability);
206	
207	        if (is_array($callback) && isset($callback[0]) && is_string($callback[0])) {
208	            $callback = $callback[0].'@'.$callback[1];
209	        }
210	
211	        if (is_callable($callback)) {
212	            $this->abilities[$ability] = $callback;
213	        } elseif (is_string($callback)) {
214	            $this->stringCallbacks[$ability] = $callback;
215	
216	            $this->abilities[$ability] = $this->buildAbilityCallback($ability, $callback);
217	        } else {
218	            throw new InvalidArgumentException("Callback must be a callable, callback array, or a 'Class@method' string.");
219	        }
220	
221	        return $this;
222	    }
223	
224	    /**
225	     * Define abilities for a resource.
226	     *
227	     * @param  string  $name
228	     * @param  string  $class
229	     * @param  array|null  $abilities
230	     * @return $this
231	     */
232	    public function resource($name, $class, ?array $abilities = null)
233	    {
234	        $abilities = $abilities ?: [
235	            'viewAny' => 'viewAny',
236	            'view' => 'view',
237	            'create' => 'create',
238	            'update' => 'update',
239	            'delete' => 'delete',
240	        ];
241	
242	        foreach ($abilities as $ability => $method) {
243	            $this->define($name.'.'.$ability, $class.'@'.$method);
244	        }
245	
246	        return $this;
247	    }
248	
249	    /**
250	     * Create the ability callback for a callback string.
251	     *
252	     * @param  string  $ability
253	     * @param  string  $callback
254	     * @return \Closure
255	     */
256	    protected function buildAbilityCallback($ability, $callback)
257	    {
258	        return function () use ($ability, $callback) {
259	            if (str_contains($callback, '@')) {
260	                [$class, $method] = Str::parseCallback($callback);
261	            } else {
262	                $class = $callback;
263	            }
264	
265	            $policy = $this->resolvePolicy($class);
266	
267	            $arguments = func_get_args();
268	
269	            $user = array_shift($arguments);
270	
271	            $result = $this->callPolicyBefore(
272	                $policy, $user, $ability, $arguments
273	            );
274	
275	            if (! is_null($result)) {
276	                return $result;
277	            }
278	
279	            return isset($method)
280	                ? $policy->{$method}(...func_get_args())
281	                : $policy(...func_get_args());
282	        };
283	    }
