285	    /**
286	     * Define a policy class for a given class type.
287	     *
288	     * @param  string  $class
289	     * @param  string  $policy
290	     * @return $this
291	     */
292	    public function policy($class, $policy)
293	    {
294	        $this->policies[$class] = $policy;
295	
296	        return $this;
297	    }
