299	    /**
300	     * Register a callback to run before all Gate checks.
301	     *
302	     * @param  callable  $callback
303	     * @return $this
304	     */
305	    public function before(callable $callback)
306	    {
307	        $this->beforeCallbacks[] = $callback;
308	
309	        return $this;
310	    }
311	
312	    /**
313	     * Register a callback to run after all Gate checks.
314	     *
315	     * @param  callable  $callback
316	     * @return $this
317	     */
318	    public function after(callable $callback)
319	    {
320	        $this->afterCallbacks[] = $callback;
321	
322	        return $this;
323	    }
