325	    /**
326	     * Determine if all of the given abilities should be granted for the current user.
327	     *
328	     * @param  iterable|\UnitEnum|string  $ability
329	     * @param  mixed  $arguments
330	     * @return bool
331	     */
332	    public function allows($ability, $arguments = [])
333	    {
334	        return $this->check($ability, $arguments);
335	    }
336	
337	    /**
338	     * Determine if any of the given abilities should be denied for the current user.
339	     *
340	     * @param  iterable|\UnitEnum|string  $ability
341	     * @param  mixed  $arguments
342	     * @return bool
343	     */
344	    public function denies($ability, $arguments = [])
345	    {
346	        return ! $this->allows($ability, $arguments);
347	    }
348	
349	    /**
350	     * Determine if all of the given abilities should be granted for the current user.
351	     *
352	     * @param  iterable|\UnitEnum|string  $abilities
353	     * @param  mixed  $arguments
354	     * @return bool
355	     */
356	    public function check($abilities, $arguments = [])
357	    {
358	        return (new Collection($abilities))->every(
359	            fn ($ability) => $this->inspect($ability, $arguments)->allowed()
360	        );
361	    }
362	
363	    /**
364	     * Determine if any one of the given abilities should be granted for the current user.
365	     *
366	     * @param  iterable|\UnitEnum|string  $abilities
367	     * @param  mixed  $arguments
368	     * @return bool
369	     */
370	    public function any($abilities, $arguments = [])
371	    {
372	        return (new Collection($abilities))->contains(fn ($ability) => $this->check($ability, $arguments));
373	    }
374	
375	    /**
376	     * Determine if all of the given abilities should be denied for the current user.
377	     *
378	     * @param  iterable|\UnitEnum|string  $abilities
379	     * @param  mixed  $arguments
380	     * @return bool
381	     */
382	    public function none($abilities, $arguments = [])
383	    {
384	        return ! $this->any($abilities, $arguments);
385	    }
386	
387	    /**
388	     * Determine if the given ability should be granted for the current user.
389	     *
390	     * @param  \UnitEnum|string  $ability
391	     * @param  mixed  $arguments
392	     * @return \Illuminate\Auth\Access\Response
393	     *
394	     * @throws \Illuminate\Auth\Access\AuthorizationException
395	     */
396	    public function authorize($ability, $arguments = [])
397	    {
398	        return $this->inspect($ability, $arguments)->authorize();
399	    }
400	
401	    /**
402	     * Inspect the user for the given ability.
403	     *
404	     * @param  \UnitEnum|string  $ability
405	     * @param  mixed  $arguments
406	     * @return \Illuminate\Auth\Access\Response
407	     */
408	    public function inspect($ability, $arguments = [])
409	    {
410	        try {
411	            $result = $this->raw(enum_value($ability), $arguments);
412	
413	            if ($result instanceof Response) {
414	                return $result;
415	            }
416	
417	            return $result
418	                ? Response::allow()
419	                : ($this->defaultDenialResponse ?? Response::deny());
420	        } catch (AuthorizationException $e) {
421	            return $e->toResponse();
422	        }
423	    }
424	
425	    /**
426	     * Get the raw result from the authorization callback.
427	     *
428	     * @param  string  $ability
429	     * @param  mixed  $arguments
430	     * @return mixed
431	     *
432	     * @throws \Illuminate\Auth\Access\AuthorizationException
433	     */
434	    public function raw($ability, $arguments = [])
435	    {
436	        $arguments = Arr::wrap($arguments);
437	
438	        $user = $this->resolveUser();
439	
440	        // First we will call the "before" callbacks for the Gate. If any of these give
441	        // back a non-null response, we will immediately return that result in order
442	        // to let the developers override all checks for some authorization cases.
443	        $result = $this->callBeforeCallbacks(
444	            $user, $ability, $arguments
445	        );
446	
447	        if (is_null($result)) {
448	            $result = $this->callAuthCallback($user, $ability, $arguments);
449	        }
450	
451	        // After calling the authorization callback, we will call the "after" callbacks
452	        // that are registered with the Gate, which allows a developer to do logging
453	        // if that is required for this application. Then we'll return the result.
454	        return tap($this->callAfterCallbacks(
455	            $user, $ability, $arguments, $result
456	        ), function ($result) use ($user, $ability, $arguments) {
457	            $this->dispatchGateEvaluatedEvent($user, $ability, $arguments, $result);
458	        });
459	    }
460	
461	    /**
462	     * Determine whether the callback/method can be called with the given user.
463	     *
464	     * @param  \Illuminate\Contracts\Auth\Authenticatable|null  $user
465	     * @param  \Closure|string|array  $class
466	     * @param  string|null  $method
467	     * @return bool
468	     */
469	    protected function canBeCalledWithUser($user, $class, $method = null)
470	    {
471	        if (! is_null($user)) {
472	            return true;
473	        }
474	
475	        if (! is_null($method)) {
476	            return $this->methodAllowsGuests($class, $method);
477	        }
478	
479	        if (is_array($class)) {
480	            $className = is_string($class[0]) ? $class[0] : get_class($class[0]);
481	
482	            return $this->methodAllowsGuests($className, $class[1]);
483	        }
484	
485	        return $this->callbackAllowsGuests($class);
486	    }
487	
488	    /**
489	     * Determine if the given class method allows guests.
490	     *
491	     * @param  string  $class
492	     * @param  string  $method
493	     * @return bool
494	     */
495	    protected function methodAllowsGuests($class, $method)
496	    {
497	        try {
498	            $reflection = new ReflectionClass($class);
499	
500	            $method = $reflection->getMethod($method);
501	        } catch (Exception) {
502	            return false;
503	        }
504	
505	        if ($method) {
506	            $parameters = $method->getParameters();
507	
508	            return isset($parameters[0]) && $this->parameterAllowsGuests($parameters[0]);
509	        }
510	
511	        return false;
512	    }
513	
514	    /**
515	     * Determine if the callback allows guests.
516	     *
517	     * @param  callable  $callback
518	     * @return bool
519	     *
520	     * @throws \ReflectionException
521	     */
522	    protected function callbackAllowsGuests($callback)
523	    {
524	        $parameters = (new ReflectionFunction($callback))->getParameters();
525	
526	        return isset($parameters[0]) && $this->parameterAllowsGuests($parameters[0]);
527	    }
528	
529	    /**
530	     * Determine if the given parameter allows guests.
531	     *
532	     * @param  \ReflectionParameter  $parameter
533	     * @return bool
534	     */
535	    protected function parameterAllowsGuests($parameter)
536	    {
537	        return ($parameter->hasType() && $parameter->allowsNull()) ||
538	               ($parameter->isDefaultValueAvailable() && is_null($parameter->getDefaultValue()));
539	    }
540	
541	    /**
542	     * Resolve and call the appropriate authorization callback.
543	     *
544	     * @param  \Illuminate\Contracts\Auth\Authenticatable|null  $user
545	     * @param  string  $ability
546	     * @param  array  $arguments
547	     * @return bool
548	     */
549	    protected function callAuthCallback($user, $ability, array $arguments)
550	    {
551	        $callback = $this->resolveAuthCallback($user, $ability, $arguments);
552	
553	        return $callback($user, ...$arguments);
554	    }
555	
556	    /**
557	     * Call all of the before callbacks and return if a result is given.
558	     *
559	     * @param  \Illuminate\Contracts\Auth\Authenticatable|null  $user
560	     * @param  string  $ability
561	     * @param  array  $arguments
562	     * @return bool|null
563	     */
564	    protected function callBeforeCallbacks($user, $ability, array $arguments)
565	    {
566	        foreach ($this->beforeCallbacks as $before) {
567	            if (! $this->canBeCalledWithUser($user, $before)) {
568	                continue;
569	            }
570	
571	            if (! is_null($result = $before($user, $ability, $arguments))) {
572	                return $result;
573	            }
574	        }
575	    }
576	
577	    /**
578	     * Call all of the after callbacks with check result.
579	     *
580	     * @param  \Illuminate\Contracts\Auth\Authenticatable  $user
581	     * @param  string  $ability
582	     * @param  array  $arguments
583	     * @param  bool|null  $result
584	     * @return bool|null
585	     */
586	    protected function callAfterCallbacks($user, $ability, array $arguments, $result)
587	    {
588	        foreach ($this->afterCallbacks as $after) {
589	            if (! $this->canBeCalledWithUser($user, $after)) {
590	                continue;
591	            }
592	
593	            $afterResult = $after($user, $ability, $result, $arguments);
594	
595	            $result ??= $afterResult;
596	        }
597	
598	        return $result;
599	    }
600	
601	    /**
602	     * Dispatch a gate evaluation event.
603	     *
604	     * @param  \Illuminate\Contracts\Auth\Authenticatable|null  $user
605	     * @param  string  $ability
606	     * @param  array  $arguments
607	     * @param  bool|null  $result
608	     * @return void
609	     */
610	    protected function dispatchGateEvaluatedEvent($user, $ability, array $arguments, $result)
611	    {
612	        if ($this->container->bound(Dispatcher::class)) {
613	            $this->container->make(Dispatcher::class)->dispatch(
614	                new GateEvaluated($user, $ability, $result, $arguments)
615	            );
616	        }
617	    }
618	
619	    /**
620	     * Resolve the callable for the given ability and arguments.
621	     *
622	     * @param  \Illuminate\Contracts\Auth\Authenticatable|null  $user
623	     * @param  string  $ability
624	     * @param  array  $arguments
625	     * @return callable
626	     */
627	    protected function resolveAuthCallback($user, $ability, array $arguments)
628	    {
629	        if (isset($arguments[0]) &&
630	            ! is_null($policy = $this->getPolicyFor($arguments[0])) &&
631	            $callback = $this->resolvePolicyCallback($user, $ability, $arguments, $policy)) {
632	            return $callback;
633	        }
634	
635	        if (isset($this->stringCallbacks[$ability])) {
636	            [$class, $method] = Str::parseCallback($this->stringCallbacks[$ability]);
637	
638	            if ($this->canBeCalledWithUser($user, $class, $method ?: '__invoke')) {
639	                return $this->abilities[$ability];
640	            }
641	        }
642	
643	        if (isset($this->abilities[$ability]) &&
644	            $this->canBeCalledWithUser($user, $this->abilities[$ability])) {
645	            return $this->abilities[$ability];
646	        }
647	
648	        return function () {
649	            //
650	        };
651	    }
652	
653	    /**
654	     * Get a policy instance for a given class.
655	     *
656	     * @param  object|string  $class
657	     * @return mixed
658	     */
659	    public function getPolicyFor($class)
660	    {
661	        if (is_object($class)) {
662	            $class = get_class($class);
663	        }
664	
665	        if (! is_string($class)) {
666	            return;
667	        }
668	
669	        if (isset($this->policies[$class])) {
670	            return $this->resolvePolicy($this->policies[$class]);
671	        }
672	
673	        $policy = $this->getPolicyFromAttribute($class);
674	
675	        if (! is_null($policy)) {
676	            return $this->resolvePolicy($policy);
677	        }
678	
679	        foreach ($this->guessPolicyName($class) as $guessedPolicy) {
680	            if (class_exists($guessedPolicy)) {
681	                return $this->resolvePolicy($guessedPolicy);
682	            }
683	        }
684	
685	        foreach ($this->policies as $expected => $policy) {
686	            if (is_subclass_of($class, $expected)) {
687	                return $this->resolvePolicy($policy);
688	            }
689	        }
690	    }
691	
692	    /**
693	     * Get the policy class from the class attribute.
694	     *
695	     * @param  class-string<*>  $class
696	     * @return class-string<*>|null
697	     */
698	    protected function getPolicyFromAttribute(string $class): ?string
699	    {
700	        if (! class_exists($class)) {
701	            return null;
702	        }
703	
704	        $attributes = (new ReflectionClass($class))->getAttributes(UsePolicy::class);
705	
706	        return $attributes !== []
707	            ? $attributes[0]->newInstance()->class
708	            : null;
709	    }
710	
711	    /**
712	     * Guess the policy name for the given class.
713	     *
714	     * @param  string  $class
715	     * @return array
716	     */
717	    protected function guessPolicyName($class)
718	    {
719	        if ($this->guessPolicyNamesUsingCallback) {
720	            return Arr::wrap(call_user_func($this->guessPolicyNamesUsingCallback, $class));
721	        }
722	
723	        $classDirname = str_replace('/', '\\', dirname(str_replace('\\', '/', $class)));
724	
725	        $classDirnameSegments = explode('\\', $classDirname);
726	
727	        return Arr::wrap(Collection::times(count($classDirnameSegments), function ($index) use ($class, $classDirnameSegments) {
728	            $classDirname = implode('\\', array_slice($classDirnameSegments, 0, $index));
729	
730	            return $classDirname.'\\Policies\\'.class_basename($class).'Policy';
